// detailPrimaryAction picks the single state-aware "primary" action for the
// bottom bar. Mirrors TUI semantics:
//   - pending          → start  (forward, primary)
//   - executing        → abort  (the only safe manual move; done is intentionally hidden)
//   - done             → reopen+rerun (both primary; see TaskActionBar)
//   - aborted          → rerun  (re-create + restart)
//
// Returns ("", "") when no primary action applies.
func detailPrimaryAction(task *orchestrator.Task, availableActions []string) (action, label string) {
	switch task.Status {
	case orchestrator.TaskStatusPending:
		for _, a := range availableActions {
			if a == "start" {
				return "start", "Start"
			}
		}
	case orchestrator.TaskStatusExecuting:
		for _, a := range availableActions {
			if a == "abort" {
				return "abort", "Abort"
			}
		}
	case orchestrator.TaskStatusAborted:
		return "rerun", "Rerun"
	}
	return "", ""
}

// actionPrimaryClass picks the visual variant for the primary bottom-bar
// button: blue for forward (start), red for destructive (abort), neutral
// for re-execute (rerun).
func actionPrimaryClass(action string) string {
	switch action {
	case "start":
		return "btn btn-primary"
	case "abort":
		return "btn btn-danger"
	default:
		return "btn btn-secondary"
	}
}

// DepsTreeRow is one row in a flattened dependency tree (either the
// upstream "depends on" tree or the downstream "dependents" tree).
// Rows are emitted in pre-order DFS with direct deps/dependents at
// depth 0 and deeper chain members at depth 1, 2, … — i.e., the same
// "parent above, child indented below" layout as the Open-tab task list.
type DepsTreeRow struct {
	Task  *orchestrator.Task
	Depth int
}

