// timelineEventTime returns the HH:MM:SS event timestamp, or dashes when
// the event predates the tracked timestamp range. Consistent format with
// status-group headers so the right column aligns visually like the TUI.
func timelineEventTime(ev timeline.Event) string {
	if !ev.HasTime {
		return "--:--:--"
	}
	return ev.Time.Format("15:04:05")
}

// timelineGroupTime formats the time the task entered a status. Same HH:MM:SS
// format as events so header and body share one visual time column.
func timelineGroupTime(g timeline.StatusGroup) string {
	if !g.HasEnteredAt {
		return "--:--:--"
	}
	return g.EnteredAt.Format("15:04:05")
}

// timelineJobStatusClass returns the job-status suffix used for marker
// coloring (completed / failed / running / default) so CSS can match both
// kind and status in a single selector.
func timelineJobStatusClass(ev timeline.Event) string {
	if ev.Job != nil && ev.Job.Status != "" {
		return ev.Job.Status
	}
	return "default"
}

// timelineJobIdentity returns the "[role] handler" prefix used as the
// running-job label (no elapsed duration — that lives in a separate span
// so JS can tick it once per second). Falls back to just the role when
// handler_id is empty, and to "job" when role is also empty.
func timelineJobIdentity(ev timeline.Event) string {
	if ev.Job == nil {
		return ""
	}
	role := ev.Job.Role
	if role == "" {
		role = "job"
	}
	if ev.Job.HandlerID != "" {
		return fmt.Sprintf("[%s] %s", role, ev.Job.HandlerID)
	}
	return fmt.Sprintf("[%s]", role)
}

// timelineJobSinceUnix returns the job's CreatedAt as a unix-seconds string
// for the data-since attribute on the dynamic-elapsed span. The client
// ticker reads it each second and rewrites the span's text; using unix
// seconds sidesteps timezone parsing in the browser.
func timelineJobSinceUnix(ev timeline.Event) string {
	if ev.Job == nil || ev.Job.CreatedAt.IsZero() {
		return ""
	}
	return fmt.Sprintf("%d", ev.Job.CreatedAt.Unix())
}

